-- ========================================\n-- 删除冗余字段，使数据库与实体类严格一致\n-- 生成日期: 2026-03-05\n-- 版本: V2.0\n--\n-- 说明: 删除实体类中不存在的数据库字段\n-- 警告: 执行前请备份数据库！\n-- ========================================\n\nSET @dbname = 'scholarship';\n\n-- ========================================\n-- 1. evaluation_result 表\n-- ========================================\n\n-- 1.1 删除 status 字段（实体类使用 resultStatus）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_result' AND COLUMN_NAME = 'status') > 0,\n    'ALTER TABLE evaluation_result DROP COLUMN status',\n    'SELECT \'[跳过] evaluation_result.status 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 1.2 删除 version 字段（实体类无此字段）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_result' AND COLUMN_NAME = 'version') > 0,\n    'ALTER TABLE evaluation_result DROP COLUMN version',\n    'SELECT \'[跳过] evaluation_result.version 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 1.3 删除 scholarship_amount 字段（实体类使用 awardAmount，保留 award_amount）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_result' AND COLUMN_NAME = 'scholarship_amount') > 0,\n    'ALTER TABLE evaluation_result DROP COLUMN scholarship_amount',\n    'SELECT \'[跳过] evaluation_result.scholarship_amount 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 1.4 删除 publish_date 字段（实体类使用 publicityDate）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_result' AND COLUMN_NAME = 'publish_date') > 0,\n    'ALTER TABLE evaluation_result DROP COLUMN publish_date',\n    'SELECT \'[跳过] evaluation_result.publish_date 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- ========================================\n-- 2. research_patent 表\n-- ========================================\n\n-- 2.1 删除 status 字段（实体类使用 auditStatus）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_patent' AND COLUMN_NAME = 'status') > 0,\n    'ALTER TABLE research_patent DROP COLUMN status',\n    'SELECT \'[跳过] research_patent.status 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.2 删除 version 字段（实体类无此字段）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_patent' AND COLUMN_NAME = 'version') > 0,\n    'ALTER TABLE research_patent DROP COLUMN version',\n    'SELECT \'[跳过] research_patent.version 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.3 删除 authorization_date_new 字段\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_patent' AND COLUMN_NAME = 'authorization_date_new') > 0,\n    'ALTER TABLE research_patent DROP COLUMN authorization_date_new',\n    'SELECT \'[跳过] research_patent.authorization_date_new 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.4 删除 review_comment 字段（实体类使用 auditComment）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_patent' AND COLUMN_NAME = 'review_comment') > 0,\n    'ALTER TABLE research_patent DROP COLUMN review_comment',\n    'SELECT \'[跳过] research_patent.review_comment 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.5 删除 reviewer_id 字段（实体类使用 auditorId）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_patent' AND COLUMN_NAME = 'reviewer_id') > 0,\n    'ALTER TABLE research_patent DROP COLUMN reviewer_id',\n    'SELECT \'[跳过] research_patent.reviewer_id 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.6 删除 review_time 字段（实体类使用 auditTime）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_patent' AND COLUMN_NAME = 'review_time') > 0,\n    'ALTER TABLE research_patent DROP COLUMN review_time',\n    'SELECT \'[跳过] research_patent.review_time 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- ========================================\n-- 3. research_project 表\n-- ========================================\n\n-- 3.1 删除 status 字段（实体类使用 auditStatus）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'status') > 0,\n    'ALTER TABLE research_project DROP COLUMN status',\n    'SELECT \'[跳过] research_project.status 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.2 删除 version 字段（实体类无此字段）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'version') > 0,\n    'ALTER TABLE research_project DROP COLUMN version',\n    'SELECT \'[跳过] research_project.version 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.3 删除 leader_name_new 字段\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'leader_name_new') > 0,\n    'ALTER TABLE research_project DROP COLUMN leader_name_new',\n    'SELECT \'[跳过] research_project.leader_name_new 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.4 删除 attachment_url 字段（实体类使用 proofMaterials）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'attachment_url') > 0,\n    'ALTER TABLE research_project DROP COLUMN attachment_url',\n    'SELECT \'[跳过] research_project.attachment_url 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.5 删除 review_comment 字段（实体类使用 auditComment）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'review_comment') > 0,\n    'ALTER TABLE research_project DROP COLUMN review_comment',\n    'SELECT \'[跳过] research_project.review_comment 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.6 删除 reviewer_id 字段（实体类使用 auditorId）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'reviewer_id') > 0,\n    'ALTER TABLE research_project DROP COLUMN reviewer_id',\n    'SELECT \'[跳过] research_project.reviewer_id 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.7 删除 review_time 字段（实体类使用 auditTime）\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'research_project' AND COLUMN_NAME = 'review_time') > 0,\n    'ALTER TABLE research_project DROP COLUMN review_time',\n    'SELECT \'[跳过] research_project.review_time 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- ========================================\n-- 执行完成提示\n-- ========================================\nSELECT 'Migration V2.0 completed successfully!' AS status;\nSELECT 'Removed redundant fields to align database with entity classes.' AS message;\n